import{_ as a,o as t,c as i,ag as l}from"./chunks/framework.B9unkguw.js";const g=JSON.parse('{"title":"Failsafes (ArduPilot)","description":"","frontmatter":{},"headers":[],"relativePath":"tr/qgc-user-guide/setup_view/ardupilot/failsafes.md","filePath":"tr/qgc-user-guide/setup_view/ardupilot/failsafes.md"}'),r={name:"tr/qgc-user-guide/setup_view/ardupilot/failsafes.md"};function s(o,e,n,h,f,c){return t(),i("div",null,e[0]||(e[0]=[l('<h1 id="failsafes-ardupilot" tabindex="-1">Failsafes (ArduPilot) <a class="header-anchor" href="#failsafes-ardupilot" aria-label="Permalink to &quot;Failsafes (ArduPilot)&quot;">​</a></h1><p>The Failsafes page configures automatic safety actions that trigger when critical systems fail. The available failsafe options vary by vehicle type.</p><h2 id="battery-failsafe" tabindex="-1">Battery Failsafe <a class="header-anchor" href="#battery-failsafe" aria-label="Permalink to &quot;Battery Failsafe&quot;">​</a></h2><p>Configurable per battery (if multiple batteries are present):</p><ul><li><strong>Low battery action</strong> — what to do when the battery reaches low level (RTL / Land / SmartRTL / etc.)</li><li><strong>Critical battery action</strong> — what to do when the battery reaches critical level</li><li><strong>Low/Critical voltage thresholds</strong> — voltage levels that trigger each action</li><li><strong>Low/Critical capacity thresholds</strong> — remaining mAh levels that trigger each action</li></ul><h2 id="ground-station-failsafe" tabindex="-1">Ground Station Failsafe <a class="header-anchor" href="#ground-station-failsafe" aria-label="Permalink to &quot;Ground Station Failsafe&quot;">​</a></h2><ul><li><strong>GCS failsafe enable</strong> — action when GCS heartbeat is lost</li><li><strong>GCS timeout</strong> — time without heartbeat before triggering (Copter/Rover)</li><li><strong>Trigger method</strong> — Heartbeat only / Heartbeat + RSSI / Heartbeat + AUTO mode (Plane)</li></ul><h2 id="throttle-failsafe" tabindex="-1">Throttle Failsafe <a class="header-anchor" href="#throttle-failsafe" aria-label="Permalink to &quot;Throttle Failsafe&quot;">​</a></h2><ul><li><strong>Throttle failsafe enable</strong> — action when RC throttle signal is lost</li><li><strong>Throttle failsafe value</strong> — PWM value that indicates signal loss</li><li>Additional options vary by vehicle type (short/long action timeouts for Plane, etc.)</li></ul><h2 id="ekf-failsafe" tabindex="-1">EKF Failsafe <a class="header-anchor" href="#ekf-failsafe" aria-label="Permalink to &quot;EKF Failsafe&quot;">​</a></h2><ul><li><strong>EKF failsafe action</strong> — action when the EKF position/velocity estimate becomes unreliable (Land / AltHold / Hold)</li><li><strong>EKF variance threshold</strong> — EKF variance level that triggers the failsafe</li></ul><h2 id="other-failsafes" tabindex="-1">Other Failsafes <a class="header-anchor" href="#other-failsafes" aria-label="Permalink to &quot;Other Failsafes&quot;">​</a></h2><p>Depending on vehicle type, additional failsafes may include:</p><ul><li><strong>Dead Reckoning</strong> (Copter) — action and timeout when GPS is lost</li><li><strong>Crash Check</strong> — detect and respond to crashes</li><li><strong>Vibration</strong> — detect excessive vibration</li><li><strong>Leak Detection</strong> (Submarine) — pin and logic level for leak sensors</li><li><strong>Internal Temperature / Pressure</strong> (Submarine) — environmental limits</li></ul>',14)]))}const u=a(r,[["render",s]]);export{g as __pageData,u as default};
